export enum UserRole {
  PATIENT = 'PATIENT',
  CARETAKER = 'CARETAKER',
  DOCTOR = 'DOCTOR'
}

export interface User {
  id: string;
  username: string;
  name: string;
  role: UserRole;
  password?: string; // Optional because we don't want to pass it around after auth
}

export interface Medicine {
  id: string;
  name: string;
  dosage: string;
  time: string; // HH:mm format
  frequency: 'daily' | 'weekly' | 'custom';
  instructions: string;
  startDate: string;
  category: 'tablet' | 'syrup' | 'injection' | 'other';
}

export interface IntakeLog {
  id: string;
  medicineId: string;
  timestamp: string;
  status: 'taken' | 'missed' | 'delayed';
  note?: string;
}

export interface AppState {
  role: UserRole;
  medicines: Medicine[];
  logs: IntakeLog[];
}

import React, { useState, useEffect, useCallback } from 'react';
import { UserRole, Medicine, IntakeLog, User } from './types';
import { INITIAL_MEDICINES, Icons } from './constants';
import Sidebar from './components/Sidebar';
import PatientDashboard from './components/PatientDashboard';
import DoctorReports from './components/DoctorReports';
import MediBot from './components/MediBot';
import MedicineModal from './components/MedicineModal';
import NotificationToast from './components/NotificationToast';
import Auth from './components/Auth';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [activeNotification, setActiveNotification] = useState<Medicine | null>(null);

  // Load user session on mount
  useEffect(() => {
    const sessionUser = sessionStorage.getItem('active_med_user');
    if (sessionUser) {
      const parsedUser = JSON.parse(sessionUser);
      setUser(parsedUser);
    }
  }, []);

  // Load user-specific data whenever user changes
  useEffect(() => {
    if (user) {
      const savedLogs = localStorage.getItem(`med_logs_${user.id}`);
      const savedMeds = localStorage.getItem(`med_list_${user.id}`);

      setMedicines(savedMeds ? JSON.parse(savedMeds) : (user.role === UserRole.PATIENT ? INITIAL_MEDICINES : []));
      setLogs(savedLogs ? JSON.parse(savedLogs) : []);

      if (user.role === UserRole.CARETAKER || user.role === UserRole.DOCTOR) {
        setActiveTab('reports');
      } else {
        setActiveTab('dashboard');
      }

      if ("Notification" in window && Notification.permission === "default") {
        Notification.requestPermission();
      }
    } else {
      // Clear state on logout
      setMedicines([]);
      setLogs([]);
      setActiveTab('dashboard');
    }
  }, [user]);

  const handleLogout = () => {
    sessionStorage.removeItem('active_med_user');
    setUser(null);
  };

  const handleMarkStatus = useCallback((medicineId: string, status: 'taken' | 'missed') => {
    if (!user) return;
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      medicineId,
      timestamp: new Date().toISOString(),
      status
    };
    const updatedLogs = [...logs, newLog];
    setLogs(updatedLogs);
    localStorage.setItem(`med_logs_${user.id}`, JSON.stringify(updatedLogs));
  }, [logs, user]);

  // Real-time reminder check loop
  useEffect(() => {
    if (!user || user.role !== UserRole.PATIENT) return;

    const checkReminders = () => {
      const now = new Date();
      const currentHHmm = now.getHours().toString().padStart(2, '0') + ":" + now.getMinutes().toString().padStart(2, '0');
      const todayStr = now.toISOString().split('T')[0];

      medicines.forEach(med => {
        if (med.time === currentHHmm) {
          const alreadyLogged = logs.find(l => l.medicineId === med.id && l.timestamp.startsWith(todayStr));
          if (!alreadyLogged) {
            setActiveNotification(med);
            if ("Notification" in window && Notification.permission === "granted") {
              new Notification(`Time for ${med.name}`, {
                body: `Dosage: ${med.dosage}. ${med.instructions}`,
                icon: 'https://cdn-icons-png.flaticon.com/512/822/822143.png'
              });
            }
          }
        }
      });
    };

    const interval = setInterval(checkReminders, 60000);
    return () => clearInterval(interval);
  }, [medicines, logs, user]);

  const handleSaveMedicine = (medicine: Medicine) => {
    if (!user) return;
    let updatedMeds;
    if (editingMedicine) {
      updatedMeds = medicines.map(m => m.id === medicine.id ? medicine : m);
    } else {
      updatedMeds = [...medicines, medicine];
    }
    setMedicines(updatedMeds);
    localStorage.setItem(`med_list_${user.id}`, JSON.stringify(updatedMeds));
    setEditingMedicine(null);
  };

  const handleDeleteMedicine = (id: string) => {
    if (!user) return;
    const updatedMeds = medicines.filter(m => m.id !== id);
    setMedicines(updatedMeds);
    localStorage.setItem(`med_list_${user.id}`, JSON.stringify(updatedMeds));
    setEditingMedicine(null);
  };

  const openAddModal = () => {
    setEditingMedicine(null);
    setIsModalOpen(true);
  };

  const openEditModal = (medicine: Medicine) => {
    setEditingMedicine(medicine);
    setIsModalOpen(true);
  };

  if (!user) {
    return <Auth onLogin={(u) => {
      setUser(u);
      sessionStorage.setItem('active_med_user', JSON.stringify(u));
    }} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <PatientDashboard medicines={medicines} logs={logs} onMarkStatus={handleMarkStatus} userName={user.name} />;
      case 'medicines':
        return (
          <div className="bg-white rounded-3xl p-8 border border-slate-200">
            <div className="flex justify-between items-center mb-6">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Your Medications</h2>
                <p className="text-slate-500 text-sm">Manage and track your prescriptions</p>
              </div>
              <button 
                onClick={openAddModal}
                className="bg-blue-600 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-sm font-bold shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95"
              >
                <Icons.Plus /> Add New
              </button>
            </div>

            {medicines.length === 0 ? (
              <div className="text-center py-20 border-2 border-dashed border-slate-100 rounded-3xl">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
                  <Icons.Pill />
                </div>
                <h3 className="font-bold text-slate-600">No medicines found</h3>
                <p className="text-sm text-slate-400">Click the button above to add your first prescription.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {medicines.map(med => (
                  <div key={med.id} className="p-5 border border-slate-100 rounded-2xl bg-slate-50 flex justify-between items-center hover:border-blue-200 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-blue-600 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                        <Icons.Pill />
                      </div>
                      <div>
                        <h4 className="font-bold text-slate-800">{med.name}</h4>
                        <p className="text-xs text-slate-500 font-medium">
                          {med.dosage} • <span className="text-blue-600">{med.time}</span>
                        </p>
                        {med.instructions && <p className="text-[10px] text-slate-400 mt-1 line-clamp-1 italic">{med.instructions}</p>}
                      </div>
                    </div>
                    <button 
                      onClick={() => openEditModal(med)}
                      className="text-slate-300 hover:text-blue-600 p-2 hover:bg-blue-50 rounded-lg transition-colors"
                      title="Edit Settings"
                    >
                      <Icons.Settings />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      case 'assistant':
        return <MediBot userName={user.name} />;
      case 'reports':
        return <DoctorReports medicines={medicines} logs={logs} userName={user.name} />;
      default:
        return <PatientDashboard medicines={medicines} logs={logs} onMarkStatus={handleMarkStatus} userName={user.name} />;
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-50">
      <Sidebar 
        currentRole={user.role} 
        onRoleChange={(newRole) => {
          const updated = { ...user, role: newRole };
          setUser(updated);
          // Update persistent storage for the session
          sessionStorage.setItem('active_med_user', JSON.stringify(updated));
          // Also update the global users list if needed, but for roles switching view is often enough
        }} 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        user={user}
        onLogout={handleLogout}
      />

      <main className="flex-1 p-4 md:ml-64 lg:p-10 pt-20 md:pt-10">
        <div className="max-w-6xl mx-auto pb-20 md:pb-0">
          {renderContent()}
        </div>
      </main>

      {activeNotification && (
        <NotificationToast 
          medicine={activeNotification} 
          onClose={() => setActiveNotification(null)}
          onTaken={(id) => handleMarkStatus(id, 'taken')}
        />
      )}

      <MedicineModal 
        isOpen={isModalOpen} 
        onClose={() => {
          setIsModalOpen(false);
          setEditingMedicine(null);
        }} 
        onSave={handleSaveMedicine}
        onDelete={handleDeleteMedicine}
        initialData={editingMedicine}
      />

      {/* Mobile Bottom Nav */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex md:hidden justify-around p-3 z-50">
        {[
          { id: 'dashboard', icon: <Icons.Calendar /> },
          { id: 'medicines', icon: <Icons.Pill /> },
          { id: 'assistant', icon: <Icons.Bot /> },
          { id: 'reports', icon: <Icons.Chart /> },
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => setActiveTab(item.id)}
            className={`p-3 rounded-xl transition-colors ${activeTab === item.id ? 'bg-blue-50 text-blue-600' : 'text-slate-400'}`}
          >
            {item.icon}
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole, User } from '../types';
import { Icons } from '../constants';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState<UserRole>(UserRole.PATIENT);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  const getAllUsers = (): (User & { password?: string })[] => {
    const users = localStorage.getItem('med_all_users');
    return users ? JSON.parse(users) : [];
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!username || !password || (!isLogin && !name)) {
      setError('Please fill in all fields');
      return;
    }

    const allUsers = getAllUsers();

    if (isLogin) {
      // Login Logic
      const foundUser = allUsers.find(u => u.username.toLowerCase() === username.toLowerCase());
      if (!foundUser) {
        setError('User not found');
        return;
      }
      if (foundUser.password !== password) {
        setError('Incorrect password');
        return;
      }
      // Success
      const { password: _, ...userWithoutPassword } = foundUser;
      onLogin(userWithoutPassword as User);
    } else {
      // Register Logic
      const userExists = allUsers.some(u => u.username.toLowerCase() === username.toLowerCase());
      if (userExists) {
        setError('Username already taken');
        return;
      }

      const newUser: User & { password?: string } = {
        id: Math.random().toString(36).substr(2, 9),
        username,
        name,
        role,
        password
      };

      const updatedUsers = [...allUsers, newUser];
      localStorage.setItem('med_all_users', JSON.stringify(updatedUsers));

      const { password: _, ...userWithoutPassword } = newUser;
      onLogin(userWithoutPassword as User);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-6">
      <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 p-10 border border-slate-100 animate-in fade-in zoom-in duration-500">
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white text-3xl font-bold mb-4 shadow-xl shadow-blue-200">
            M
          </div>
          <h1 className="text-2xl font-black text-slate-800">MediTrack</h1>
          <p className="text-slate-500 text-sm mt-1">
            {isLogin ? 'Welcome back, please login' : 'Smart Healthcare Companion'}
          </p>
        </div>

        <form onSubmit={handleAuth} className="space-y-5">
          {!isLogin && (
            <div className="p-1 bg-slate-100 rounded-2xl flex">
              <button
                type="button"
                onClick={() => setRole(UserRole.PATIENT)}
                className={`flex-1 py-3 text-sm font-bold rounded-xl transition-all ${
                  role === UserRole.PATIENT 
                  ? 'bg-white text-blue-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                Patient
              </button>
              <button
                type="button"
                onClick={() => setRole(UserRole.CARETAKER)}
                className={`flex-1 py-3 text-sm font-bold rounded-xl transition-all ${
                  role === UserRole.CARETAKER 
                  ? 'bg-white text-blue-600 shadow-sm' 
                  : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                Caretaker
              </button>
            </div>
          )}

          <div className="space-y-4">
            {!isLogin && (
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase ml-1 mb-1.5">Full Name</label>
                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                    <Icons.User />
                  </div>
                  <input
                    required
                    type="text"
                    placeholder="Enter your name"
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl pl-12 pr-4 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                  />
                </div>
              </div>
            )}

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase ml-1 mb-1.5">Username</label>
              <input
                required
                type="text"
                placeholder="Your username"
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-4 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase ml-1 mb-1.5">Password</label>
              <input
                required
                type="password"
                placeholder="••••••••"
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-4 py-3.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </div>
          </div>

          {error && (
            <div className="p-3 bg-rose-50 text-rose-600 text-xs font-bold rounded-xl text-center border border-rose-100 animate-in fade-in slide-in-from-top-1">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-blue-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-blue-200 hover:bg-blue-700 active:scale-[0.98] transition-all mt-2"
          >
            {isLogin ? 'Login' : 'Create Account'}
          </button>

          <button
            type="button"
            onClick={() => {
              setIsLogin(!isLogin);
              setError('');
            }}
            className="w-full text-slate-400 text-xs font-bold hover:text-blue-600 transition-colors py-2"
          >
            {isLogin ? "Don't have an account? Sign up" : "Already have an account? Log in"}
          </button>
        </form>

        <p className="text-center text-[10px] text-slate-300 mt-8 uppercase tracking-widest font-black">
          MediTrack Secure Access
        </p>
      </div>
    </div>
  );
};

export default Auth;

