// Audio Helpers
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [activeNotification, setActiveNotification] = useState<Medicine | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const notifiedIdsRef = useRef<Set<string>>(new Set());

  // Initialize AudioContext on user interaction to avoid browser blocks
  const initAudio = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  }, []);

  // Load user session on mount
  useEffect(() => {
    const sessionUser = sessionStorage.getItem('active_med_user');
    if (sessionUser) {
      const parsedUser = JSON.parse(sessionUser);
      setUser(parsedUser);
    }
  }, []);

  // Load user-specific data whenever user changes
  useEffect(() => {
    if (user) {
      const savedLogs = localStorage.getItem(`med_logs_${user.id}`);
      const savedMeds = localStorage.getItem(`med_list_${user.id}`);

      setMedicines(savedMeds ? JSON.parse(savedMeds) : (user.role === UserRole.PATIENT ? INITIAL_MEDICINES : []));
      setLogs(savedLogs ? JSON.parse(savedLogs) : []);

      if (user.role === UserRole.CARETAKER || user.role === UserRole.DOCTOR) {
        setActiveTab('reports');
      } else {
        setActiveTab('dashboard');
      }

      if ("Notification" in window && Notification.permission === "default") {
        Notification.requestPermission();
      }
    } else {
      setMedicines([]);
      setLogs([]);
      setActiveTab('dashboard');
    }
  }, [user]);

  const handleLogout = () => {
    sessionStorage.removeItem('active_med_user');
    setUser(null);
    notifiedIdsRef.current.clear();
  };

  const playVoiceReminder = async (medicine: Medicine) => {
    initAudio();
    if (!audioContextRef.current) return;

    try {
      const prompt = `Hello ${user?.name || 'there'}. It is time to take your ${medicine.name}, ${medicine.dosage}. Instructions: ${medicine.instructions || 'Please take it now.'}`;
      const base64Audio = await generateVoiceReminder(prompt);

      if (base64Audio) {
        const audioBytes = decodeBase64(base64Audio);
        const audioBuffer = await decodeAudioData(audioBytes, audioContextRef.current, 24000, 1);

        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.start();
      }
    } catch (err) {
      console.error("Voice reminder failed:", err);
    }
  };

  const handleMarkStatus = useCallback((medicineId: string, status: 'taken' | 'missed') => {
    if (!user) return;
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      medicineId,
      timestamp: new Date().toISOString(),
      status
    };
    const updatedLogs = [...logs, newLog];
    setLogs(updatedLogs);
    localStorage.setItem(`med_logs_${user.id}`, JSON.stringify(updatedLogs));
  }, [logs, user]);

  // Real-time reminder check loop
  useEffect(() => {
    if (!user || user.role !== UserRole.PATIENT) return;

    const checkReminders = () => {
      const now = new Date();
      const currentHHmm = now.getHours().toString().padStart(2, '0') + ":" + now.getMinutes().toString().padStart(2, '0');
      const todayStr = now.toISOString().split('T')[0];

      medicines.forEach(med => {
        if (med.time === currentHHmm) {
          const reminderKey = `${med.id}_${todayStr}_${currentHHmm}`;
          if (notifiedIdsRef.current.has(reminderKey)) return;

          const alreadyLogged = logs.find(l => l.medicineId === med.id && l.timestamp.startsWith(todayStr));
          if (!alreadyLogged) {
            setActiveNotification(med);
            notifiedIdsRef.current.add(reminderKey);

            // Trigger Voice Note
            playVoiceReminder(med);

            if ("Notification" in window && Notification.permission === "granted") {
              new Notification(`Time for ${med.name}`, {
                body: `Dosage: ${med.dosage}. ${med.instructions}`,
                icon: 'https://cdn-icons-png.flaticon.com/512/822/822143.png'
              });
            }
          }
        }
      });
    };

    const interval = setInterval(checkReminders, 15000); // Check more frequently for better precision
    return () => clearInterval(interval);
  }, [medicines, logs, user, initAudio]);

  const handleSaveMedicine = (medicine: Medicine) => {
    if (!user) return;
    let updatedMeds;
    if (editingMedicine) {
      updatedMeds = medicines.map(m => m.id === medicine.id ? medicine : m);
    } else {
      updatedMeds = [...medicines, medicine];
    }
    setMedicines(updatedMeds);
    localStorage.setItem(`med_list_${user.id}`, JSON.stringify(updatedMeds));
    setEditingMedicine(null);
  };

  const handleDeleteMedicine = (id: string) => {
    if (!user) return;
    const updatedMeds = medicines.filter(m => m.id !== id);
    setMedicines(updatedMeds);
    localStorage.setItem(`med_list_${user.id}`, JSON.stringify(updatedMeds));
    setEditingMedicine(null);
  };

  const openAddModal = () => {
    setEditingMedicine(null);
    setIsModalOpen(true);
    initAudio(); // Prepare audio on user interaction
  };

  const openEditModal = (medicine: Medicine) => {
    setEditingMedicine(medicine);
    setIsModalOpen(true);
    initAudio(); // Prepare audio on user interaction
  };

  if (!user) {
    return <Auth onLogin={(u) => {
      setUser(u);
      sessionStorage.setItem('active_med_user', JSON.stringify(u));
      initAudio(); // User interacted with login, safe to init audio
    }} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <PatientDashboard medicines={medicines} logs={logs} onMarkStatus={handleMarkStatus} userName={user.name} />;
      case 'medicines':
        return (
          <div className="bg-white rounded-3xl p-8 border border-slate-200">
            <div className="flex justify-between items-center mb-6">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Your Medications</h2>
                <p className="text-slate-500 text-sm">Manage and track your prescriptions</p>
              </div>
              <button 
                onClick={openAddModal}
                className="bg-blue-600 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-sm font-bold shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95"
              >
                <Icons.Plus /> Add New
              </button>
            </div>

            {medicines.length === 0 ? (
              <div className="text-center py-20 border-2 border-dashed border-slate-100 rounded-3xl">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
                  <Icons.Pill />
                </div>
                <h3 className="font-bold text-slate-600">No medicines found</h3>
                <p className="text-sm text-slate-400">Click the button above to add your first prescription.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {medicines.map(med => (
                  <div key={med.id} className="p-5 border border-slate-100 rounded-2xl bg-slate-50 flex justify-between items-center hover:border-blue-200 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-blue-600 shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
                        <Icons.Pill />
                      </div>
                      <div>
                        <h4 className="font-bold text-slate-800">{med.name}</h4>
                        <p className="text-xs text-slate-500 font-medium">
                          {med.dosage} • <span className="text-blue-600">{med.time}</span>
                        </p>
                        {med.instructions && <p className="text-[10px] text-slate-400 mt-1 line-clamp-1 italic">{med.instructions}</p>}
                      </div>
                    </div>
                    <button 
                      onClick={() => openEditModal(med)}
                      className="text-slate-300 hover:text-blue-600 p-2 hover:bg-blue-50 rounded-lg transition-colors"
                      title="Edit Settings"
                    >
                      <Icons.Settings />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      case 'assistant':
        return <MediBot userName={user.name} />;
      case 'reports':
        return <DoctorReports medicines={medicines} logs={logs} userName={user.name} />;
      default:
        return <PatientDashboard medicines={medicines} logs={logs} onMarkStatus={handleMarkStatus} userName={user.name} />;
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-50">
      <Sidebar 
        currentRole={user.role} 
        onRoleChange={(newRole) => {
          const updated = { ...user, role: newRole };
          setUser(updated);
          sessionStorage.setItem('active_med_user', JSON.stringify(updated));
          initAudio();
        }} 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        user={user}
        onLogout={handleLogout}
      />

      <main className="flex-1 p-4 md:ml-64 lg:p-10 pt-20 md:pt-10">
        <div className="max-w-6xl mx-auto pb-20 md:pb-0">
          {renderContent()}
        </div>
      </main>

      {activeNotification && (
        <NotificationToast 
          medicine={activeNotification} 
          onClose={() => setActiveNotification(null)}
          onTaken={(id) => handleMarkStatus(id, 'taken')}
        />
      )}

      <MedicineModal 
        isOpen={isModalOpen} 
        onClose={() => {
          setIsModalOpen(false);
          setEditingMedicine(null);
        }} 
        onSave={handleSaveMedicine}
        onDelete={handleDeleteMedicine}
        initialData={editingMedicine}
      />

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 flex md:hidden justify-around p-3 z-50">
        {[
          { id: 'dashboard', icon: <Icons.Calendar /> },
          { id: 'medicines', icon: <Icons.Pill /> },
          { id: 'assistant', icon: <Icons.Bot /> },
          { id: 'reports', icon: <Icons.Chart /> },
        ].map(item => (
          <button 
            key={item.id}
            onClick={() => {
              setActiveTab(item.id);
              initAudio();
            }}
            className={`p-3 rounded-xl transition-colors ${activeTab === item.id ? 'bg-blue-50 text-blue-600' : 'text-slate-400'}`}
          >
            {item.icon}
          </button>
        ))}
      </nav>
    </div>
  );
};

export default App;

