              ))}
            </div>
          </div>
        );
      case 'assistant':
        return <MediBot userName={user.name} />;
      case 'reports':
        return (
          <div className="space-y-6">
            {user.role === UserRole.CARETAKER && alerts.length > 0 && (
              <div className="bg-rose-50 border border-rose-100 rounded-3xl p-6">
                <h3 className="text-rose-600 font-black mb-4 flex items-center gap-2">
                  <Icons.Bell /> Active Alerts
