import React, { useState, useEffect, useCallback, useRef } from 'react';
import { UserRole, Medicine, IntakeLog, User, CaretakerAlert } from './types';
import { INITIAL_MEDICINES, Icons } from './constants';
import Sidebar from './components/Sidebar';
import PatientDashboard from './components/PatientDashboard';
import DoctorReports from './components/DoctorReports';
import MediBot from './components/MediBot';
import MedicineModal from './components/MedicineModal';
import NotificationToast from './components/NotificationToast';
import Auth from './components/Auth';
import { generateVoiceReminder } from './services/geminiService';

// Audio Helpers
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [medicines, setMedicines] = useState<Medicine[]>([]);
  const [logs, setLogs] = useState<IntakeLog[]>([]);
  const [alerts, setAlerts] = useState<CaretakerAlert[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingMedicine, setEditingMedicine] = useState<Medicine | null>(null);
  const [activeNotification, setActiveNotification] = useState<Medicine | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  const initAudio = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  }, []);

  useEffect(() => {
    const sessionUser = sessionStorage.getItem('active_med_user');
    if (sessionUser) {
      const parsedUser = JSON.parse(sessionUser);
      setUser(parsedUser);
    }
  }, []);

  useEffect(() => {
    if (user) {
      const savedLogs = localStorage.getItem(`med_logs_${user.id}`);
      const savedMeds = localStorage.getItem(`med_list_${user.id}`);
      const savedAlerts = localStorage.getItem(`med_alerts_global`);

      setMedicines(savedMeds ? JSON.parse(savedMeds) : (user.role === UserRole.PATIENT ? INITIAL_MEDICINES : []));
      setLogs(savedLogs ? JSON.parse(savedLogs) : []);
      setAlerts(savedAlerts ? JSON.parse(savedAlerts) : []);

      if (user.role === UserRole.CARETAKER || user.role === UserRole.DOCTOR) {
        setActiveTab('reports');
      } else {
        setActiveTab('dashboard');
      }

      if ("Notification" in window && Notification.permission === "default") {
        Notification.requestPermission();
      }
    }
  }, [user]);

  const handleLogout = () => {
    sessionStorage.removeItem('active_med_user');
    setUser(null);
  };

  const playVoiceReminder = async (medicine: Medicine, isFollowUp: boolean) => {
    initAudio();
    if (!audioContextRef.current) return;

    try {
      const greeting = isFollowUp 
        ? `Attention ${user?.name}. This is a repeat reminder.` 
        : `Hello ${user?.name}. It is now time for your medication.`;

      const prompt = `${greeting} Please take ${medicine.dosage} of ${medicine.name}. ${medicine.instructions ? `Note: ${medicine.instructions}` : ''} This English voice note will repeat every 5 minutes until you confirm it is taken.`;

      const base64Audio = await generateVoiceReminder(prompt);

      if (base64Audio) {
        const audioBytes = decodeBase64(base64Audio);
        const audioBuffer = await decodeAudioData(audioBytes, audioContextRef.current, 24000, 1);

        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.start();
      }
    } catch (err) {
      console.error("Voice reminder failed:", err);
    }
  };

  const createAlert = useCallback((med: Medicine, type: 'missed' | 'unresponsive') => {
    if (!user) return;
    const newAlert: CaretakerAlert = {
      id: Math.random().toString(36).substr(2, 9),
      patientId: user.id,
      patientName: user.name,
      medicineName: med.name,
      time: med.time,
      timestamp: new Date().toISOString(),
      type
    };

    const existingAlerts = JSON.parse(localStorage.getItem(`med_alerts_global`) || '[]');
    const updatedAlerts = [newAlert, ...existingAlerts];
    setAlerts(updatedAlerts);
    localStorage.setItem(`med_alerts_global`, JSON.stringify(updatedAlerts));
  }, [user]);

  const handleMarkStatus = useCallback((medicineId: string, status: 'taken' | 'missed') => {
    if (!user) return;
    const newLog: IntakeLog = {
      id: Math.random().toString(36).substr(2, 9),
      medicineId,
      timestamp: new Date().toISOString(),
      status
    };

    const updatedLogs = [...logs, newLog];
    setLogs(updatedLogs);
    localStorage.setItem(`med_logs_${user.id}`, JSON.stringify(updatedLogs));

    if (status === 'missed') {
      const med = medicines.find(m => m.id === medicineId);
      if (med) createAlert(med, 'missed');
    }
  }, [logs, user, medicines, createAlert]);

  useEffect(() => {
    if (!user || user.role !== UserRole.PATIENT) return;

    const checkReminders = () => {
      const now = new Date();
      const nowTs = now.getTime();
      const todayStr = now.toISOString().split('T')[0];

      medicines.forEach(med => {
        const [medH, medM] = med.time.split(':').map(Number);
        const medTimeToday = new Date();
        medTimeToday.setHours(medH, medM, 0, 0);

        if (nowTs >= medTimeToday.getTime()) {
          const log = logs.find(l => l.medicineId === med.id && l.timestamp.startsWith(todayStr));

          if (!log) {
            const reminderKey = `remind_track_${user.id}_${med.id}_${todayStr}`;
            const lastRemindedStr = localStorage.getItem(reminderKey);
            const lastTime = lastRemindedStr ? parseInt(lastRemindedStr, 10) : 0;
            const fiveMinutesInMs = 5 * 60 * 1000;
            const sixtyMinutesInMs = 60 * 60 * 1000;

            if (lastTime === 0 || (nowTs - lastTime) >= fiveMinutesInMs) {
              const isFollowUp = lastTime !== 0;
              setActiveNotification(med);
              localStorage.setItem(reminderKey, nowTs.toString());
              playVoiceReminder(med, isFollowUp);

              if ("Notification" in window && Notification.permission === "granted") {
                new Notification(`MediTrack Reminder: ${med.name}`, {
                  body: `Time for your ${med.dosage} dose.`,
                  icon: 'https://cdn-icons-png.flaticon.com/512/822/822143.png'
                });
              }
            }

            if (nowTs - medTimeToday.getTime() > sixtyMinutesInMs) {
              const autoAlertKey = `auto_alert_track_${user.id}_${med.id}_${todayStr}`;
              if (!localStorage.getItem(autoAlertKey)) {
                createAlert(med, 'unresponsive');
                localStorage.setItem(autoAlertKey, 'true');
              }
            }
          }
        }
      });
    };

    const interval = setInterval(checkReminders, 15000);
    return () => clearInterval(interval);
  }, [medicines, logs, user, initAudio, createAlert]);

  const handleSaveMedicine = (medicine: Medicine) => {
    if (!user) return;
    let updatedMeds;
    if (editingMedicine) {
      updatedMeds = medicines.map(m => m.id === medicine.id ? medicine : m);
    } else {
      updatedMeds = [...medicines, medicine];
    }
    setMedicines(updatedMeds);
    localStorage.setItem(`med_list_${user.id}`, JSON.stringify(updatedMeds));
    setEditingMedicine(null);
  };

  const handleDeleteMedicine = (id: string) => {
    if (!user) return;
    const updatedMeds = medicines.filter(m => m.id !== id);
    setMedicines(updatedMeds);
    localStorage.setItem(`med_list_${user.id}`, JSON.stringify(updatedMeds));
    setEditingMedicine(null);
  };

  if (!user) return <Auth onLogin={(u) => { setUser(u); sessionStorage.setItem('active_med_user', JSON.stringify(u)); initAudio(); }} />;

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <PatientDashboard medicines={medicines} logs={logs} onMarkStatus={handleMarkStatus} userName={user.name} />;
      case 'medicines':
        return (
          <div className="bg-white rounded-3xl p-8 border border-slate-200">
            <div className="flex justify-between items-center mb-6">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Prescription Schedule</h2>
                <p className="text-slate-500 text-sm">Manage medication timings here</p>
              </div>
              <button onClick={() => { setEditingMedicine(null); setIsModalOpen(true); initAudio(); }} className="bg-blue-600 text-white px-5 py-2.5 rounded-xl flex items-center gap-2 text-sm font-bold shadow-lg shadow-blue-100 hover:bg-blue-700 transition-all active:scale-95">
                <Icons.Plus /> Add Medicine
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {medicines.map(med => (
                <div key={med.id} className="p-6 border border-slate-100 rounded-3xl bg-slate-50 flex flex-col justify-between hover:border-blue-200 transition-all group">
                  <div className="flex items-start justify-between mb-4">
                    <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                      <Icons.Pill />
                    </div>
                    <button onClick={() => { setEditingMedicine(med); setIsModalOpen(true); }} className="text-slate-300 hover:text-blue-600 transition-colors"><Icons.Settings /></button>
                  </div>
                  <div>
                    <h4 className="font-black text-slate-800 text-lg">{med.name}</h4>
                    <div className="flex items-center gap-2 mt-1">
                      <span className="text-blue-600 font-black text-sm">{med.time}</span>
                      <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                      <span className="text-slate-500 text-xs font-bold">{med.dosage}</span>
                    </div>
                    <p className="text-[10px] text-blue-500 font-black mt-3 uppercase tracking-widest flex items-center gap-1.5">
                      <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse"></span> Voice Active
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'assistant':
        return <MediBot userName={user.name} />;
      case 'reports':
        return (
          <div className="space-y-6">
            {user.role === UserRole.CARETAKER && alerts.length > 0 && (
              <div className="bg-blue-50 border border-blue-100 rounded-[2.5rem] p-8 shadow-xl shadow-blue-100/10">
                <h3 className="text-blue-600 font-black mb-6 flex items-center gap-3 text-xl">
                  <div className="w-10 h-10 bg-blue-500 text-white rounded-xl flex items-center justify-center">
                    <Icons.Bell />
                  </div>
                  Adherence Alerts
                </h3>
                <div className="space-y-4">
                  {alerts.map(alert => (
                    <div key={alert.id} className="bg-white p-5 rounded-2xl border border-blue-100 flex justify-between items-center shadow-sm">
                      <div>
                        <p className="text-slate-800 font-black">
                          {alert.patientName} <span className="text-blue-500 font-black uppercase text-[10px] ml-2 px-2 py-0.5 bg-blue-50 rounded-full">{alert.type}</span>
                        </p>
                        <p className="text-sm text-slate-500 mt-1">{alert.medicineName} scheduled for {alert.time}</p>
                        <p className="text-[10px] text-slate-400 font-bold mt-2 flex items-center gap-1"><Icons.Calendar /> {new Date(alert.timestamp).toLocaleString()}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
            <DoctorReports medicines={medicines} logs={logs} userName={user.name} />
          </div>
        );
      default:
        return <PatientDashboard medicines={medicines} logs={logs} onMarkStatus={handleMarkStatus} userName={user.name} />;
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-50">
      <Sidebar user={user} currentRole={user.role} onRoleChange={(r) => { const u = { ...user, role: r }; setUser(u); sessionStorage.setItem('active_med_user', JSON.stringify(u)); initAudio(); }} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} />
      <main className="flex-1 p-4 md:ml-64 lg:p-10 pt-20 md:pt-10">
        <div className="max-w-6xl mx-auto">{renderContent()}</div>
      </main>

      {activeNotification && (
        <NotificationToast 
          medicine={activeNotification} 
          onClose={() => setActiveNotification(null)} 
          onTaken={(id) => handleMarkStatus(id, 'taken')} 
        />
      )}

      <MedicineModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={handleSaveMedicine} 
        onDelete={handleDeleteMedicine} 
        initialData={editingMedicine} 
      />
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { Medicine, IntakeLog } from '../types';
import { Icons } from '../constants';

interface PatientDashboardProps {
  medicines: Medicine[];
  logs: IntakeLog[];
  onMarkStatus: (medicineId: string, status: 'taken' | 'missed') => void;
  userName: string;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ medicines, logs, onMarkStatus, userName }) => {
  const sortedMeds = useMemo(() => [...medicines].sort((a, b) => a.time.localeCompare(b.time)), [medicines]);
  const today = new Date().toISOString().split('T')[0];

  const getStatusForToday = (medId: string) => {
    return logs.find(l => l.medicineId === medId && l.timestamp.startsWith(today))?.status;
  };

  const nextDoseInfo = useMemo(() => {
    const now = new Date();
    const currentHHmm = now.getHours().toString().padStart(2, '0') + ":" + now.getMinutes().toString().padStart(2, '0');

    const next = sortedMeds.find(m => {
      const status = getStatusForToday(m.id);
      return m.time > currentHHmm && !status;
    });

    if (!next) return null;

    const [h, m] = next.time.split(':').map(Number);
    const target = new Date();
    target.setHours(h, m, 0);
    const diffMs = target.getTime() - now.getTime();
    const diffMins = Math.round(diffMs / 60000);

    return { medicine: next, minutes: diffMins };
  }, [sortedMeds, logs]);

  const firstName = userName.split(' ')[0];

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Hello, {firstName}</h1>
          <p className="text-slate-500 mt-1 font-medium flex items-center gap-2">
            You have {medicines.length} medicines scheduled today.
            <span className="bg-emerald-100 text-emerald-600 text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest">Voice Notes Enabled</span>
          </p>
        </div>
        <div className="text-right hidden sm:block">
          <p className="text-sm font-bold text-slate-800">{new Date().toLocaleDateString('en-US', { weekday: 'long' })}</p>
          <p className="text-xs font-medium text-slate-400">{new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric' })}</p>
        </div>
      </header>

      <div className={`rounded-[2.5rem] p-8 text-white flex items-center justify-between shadow-2xl transition-all duration-500 relative overflow-hidden ${
        nextDoseInfo ? 'bg-blue-600 shadow-blue-200' : 'bg-slate-800 shadow-slate-200'
      }`}>
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="relative z-10">
          {nextDoseInfo ? (
            <>
              <h2 className="text-2xl font-black mb-1">Next Dose in {nextDoseInfo.minutes} mins</h2>
              <p className="opacity-90 font-medium">{nextDoseInfo.medicine.name} • {nextDoseInfo.medicine.dosage}</p>
              <div className="mt-4 flex items-center gap-4">
                <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest bg-white/20 w-fit px-3 py-1 rounded-full">
                  <Icons.Bell /> Reminder set
                </div>
                <div className="flex items-center gap-2 text-xs font-bold uppercase tracking-widest bg-emerald-500/30 w-fit px-3 py-1 rounded-full border border-emerald-400/30">
                  <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-ping"></span>
                  Voice Reminders Active
                </div>
              </div>
            </>
          ) : (
            <>
              <h2 className="text-2xl font-black mb-1">All clear for now!</h2>
              <p className="opacity-90 font-medium">No upcoming doses scheduled for today.</p>
            </>
          )}
        </div>
        <div className="relative z-10 bg-white/10 p-5 rounded-3xl backdrop-blur-md hidden sm:block">
          {nextDoseInfo ? <Icons.Bell /> : <Icons.Check />}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-4">
          <h3 className="text-xl font-black text-slate-800 flex items-center gap-3">
            <div className="w-8 h-8 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center">
              <Icons.Calendar />
            </div>
            Today's Schedule
          </h3>

          <div className="space-y-4 relative">
            <div className="absolute left-6 top-4 bottom-4 w-0.5 bg-slate-100 -z-10"></div>
            {sortedMeds.length === 0 ? (
              <div className="bg-white p-12 rounded-[2rem] border-2 border-dashed border-slate-100 text-center">
                <p className="text-slate-400 font-bold">No medicines scheduled yet.</p>
              </div>
            ) : (
              sortedMeds.map((med) => {
                const status = getStatusForToday(med.id);
                return (
                  <div key={med.id} className="flex gap-4 group">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center z-10 shadow-sm transition-all duration-500 border-4 border-slate-50 ${
                      status === 'taken' ? 'bg-emerald-500 text-white' :
                      status === 'missed' ? 'bg-rose-500 text-white' : 'bg-white text-slate-400 border-white'
                    }`}>
                      {status === 'taken' ? <Icons.Check /> : status === 'missed' ? <Icons.X /> : <span className="font-black">{med.time.split(':')[0]}</span>}
                    </div>

                    <div className={`flex-1 bg-white border-2 rounded-[1.5rem] p-5 transition-all duration-300 ${
                      status === 'taken' ? 'border-emerald-100 opacity-60 grayscale-[0.5]' : 
                      status === 'missed' ? 'border-rose-100' : 'border-slate-50 shadow-sm hover:shadow-xl hover:border-blue-100'
                    }`}>
                      <div className="flex justify-between items-start">
                        <div>
                          <div className="flex items-center gap-2 mb-1">
                            <span className={`text-xs font-black uppercase tracking-widest ${status === 'taken' ? 'text-emerald-500' : 'text-blue-600'}`}>{med.time}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <span className="text-xs font-bold text-slate-400">{med.dosage}</span>
                          </div>
                          <h4 className={`text-lg font-black ${status === 'taken' ? 'text-slate-400 line-through' : 'text-slate-800'}`}>{med.name}</h4>
                          {med.instructions && <p className="text-sm text-slate-500 font-medium mt-1">{med.instructions}</p>}
                        </div>

                        {!status && (
                          <div className="flex gap-2">
                            <button 
                              onClick={() => onMarkStatus(med.id, 'taken')}
                              className="bg-emerald-50 text-emerald-600 p-3 rounded-xl hover:bg-emerald-500 hover:text-white transition-all shadow-sm active:scale-90"
                              title="Mark as Taken"
                            >
                              <Icons.Check />
                            </button>
                            <button 
                              onClick={() => onMarkStatus(med.id, 'missed')}
                              className="bg-rose-50 text-rose-600 p-3 rounded-xl hover:bg-rose-500 hover:text-white transition-all shadow-sm active:scale-90"
                              title="Mark as Missed"
                            >
                              <Icons.X />
                            </button>
                          </div>
                        )}
                      </div>

                      {!status && (
                        <div className="mt-4 pt-4 border-t border-slate-50 flex items-center justify-between">
                           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-widest">
                             <Icons.Bell /> 5-Min Voice Cycle Enabled
                           </div>
                           <span className="text-[9px] font-black text-blue-500 uppercase">Compulsory Reminder</span>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm h-fit">
            <h3 className="font-black text-slate-800 mb-6 flex items-center justify-between">
              Daily Progress
              <span className="text-blue-600 text-sm">Active</span>
            </h3>
            <div className="flex items-end justify-between h-32 gap-2">
              {[65, 80, 40, 90, 100, 75, 95].map((val, i) => (
                <div key={i} className="flex-1 flex flex-col items-center gap-2">
                  <div className="w-full bg-slate-50 rounded-lg overflow-hidden flex flex-col justify-end h-full">
                    <div className={`w-full transition-all duration-1000 rounded-t-lg ${val > 80 ? 'bg-emerald-400' : val > 50 ? 'bg-blue-400' : 'bg-rose-400'}`} style={{ height: `${val}%` }}></div>
                  </div>
                  <span className="text-[10px] font-black text-slate-300">{"MTWTFSS"[i]}</span>
                </div>
              ))}
            </div>
            <p className="mt-6 text-[10px] text-slate-400 font-bold uppercase tracking-widest text-center">Consistency Tracker</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PatientDashboard;
